    // Input validation
    if (typeof directory !== 'string' || typeof dest_tar_path !== 'string') {
        throw new TypeError("directory and dest_tar_path must be strings");
    }
    if (directory.trim() === '' || dest_tar_path.trim() === '') {
        throw new Error("inputs must be non-empty");
    }
    if (!dest_tar_path.endsWith('.tar')) {
        throw new Error("dest_tar_path must end with .tar");
    }

    // Reject dangerous characters
    const invalidChars = ["\x00", "\n", "\r"];
    for (const ch of invalidChars) {
        if (directory.includes(ch) || dest_tar_path.includes(ch)) {
            throw new Error("invalid characters in path");
        }
    }

    // Resolve and validate directory
    const dirAbs = path.resolve(directory);
    if (!fs.statSync(dirAbs).isDirectory()) {
        throw new Error("directory not found");
    }

    // Ensure parent of destination exists
    const destAbs = path.resolve(dest_tar_path);
    const parent = path.dirname(destAbs);
    if (!fs.existsSync(parent)) {
        throw new Error("destination directory not found");
    }

    // Create tar archive using the tar module (avoids system command injection)
    try {
        tar.c(
            {
                gzip: false,
                file: dest_tar_path,
                cwd: dirAbs,
                portable: true,
                sync: true
            },
            ['.']
        );
    } catch (e) {
        throw new Error("tar failed: " + e.message);
    }

    return `Archived to ${dest_tar_path}`;
}

